#include <stdio.h> 
#include <stdlib.h> 
#include <string.h> 
#include <stdbool.h> 

#define MAX_NAME 100 
#define MAX_FLYERS 100000 

// Status ranking: Silver=1, Gold=2, Platinum=3, Super=4 
typedef enum { 
    SILVER = 1, 
    GOLD = 2, 
    PLATINUM = 3, 
    SUPER = 4 
} Status; 

// Flyer structure 
typedef struct { 
    char name[MAX_NAME]; 
    int flyer_id; 
    int request_time; 
    Status status; 
    bool is_cancelled; 
} Flyer; 

// Max Heap for priority queue 
typedef struct { 
    Flyer* flyers[MAX_FLYERS]; 
    int size; 
    int* id_to_index; // Hash map: flyer_id -> heap index 
} PriorityQueue; 

// Function prototypes 
PriorityQueue* createPriorityQueue(); 
void destroyPriorityQueue(PriorityQueue* pq); 
Status stringToStatus(const char* status_str);

8 

int comparePriority(Flyer* f1, Flyer* f2); 
void swap(Flyer** a, Flyer** b, int* index_a, int* index_b, int* id_to_index); 
void heapifyUp(PriorityQueue* pq, int index); 
void heapifyDown(PriorityQueue* pq, int index); 
void insertFlyer(PriorityQueue* pq, Flyer* flyer); 
Flyer* extractMax(PriorityQueue* pq); 
void cancelRequest(PriorityQueue* pq, int flyer_id); 
void findTopKFlyers(PriorityQueue* pq, int k, Flyer** result, int* result_size); 

// Create priority queue 
PriorityQueue* createPriorityQueue() { 
    PriorityQueue* pq = (PriorityQueue*)malloc(sizeof(PriorityQueue)); 
    pq->size = 0; 
    pq->id_to_index = (int*)calloc(MAX_FLYERS, sizeof(int)); 
    for (int i = 0; i < MAX_FLYERS; i++) { 
        pq->id_to_index[i] = -1; // -1 means not in heap 
    } 
    return pq; 
} 

// Destroy priority queue 
void destroyPriorityQueue(PriorityQueue* pq) { 
    for (int i = 0; i < pq->size; i++) { 
        free(pq->flyers[i]); 
    } 
    free(pq->id_to_index); 
    free(pq); 
} 

// Convert status string to enum 
Status stringToStatus(const char* status_str) { 
    if (strcmp(status_str, "Super") == 0) return SUPER; 
    if (strcmp(status_str, "Platinum") == 0) return PLATINUM; 
    if (strcmp(status_str, "Gold") == 0) return GOLD; 
    return SILVER; 
} 

// Compare priority: return 1 if f1 has higher priority, -1 if f2, 0 if equal

9 

int comparePriority(Flyer* f1, Flyer* f2) { 
    if (f1->status != f2->status) { 
        return (f1->status > f2->status) ? 1 : -1; 
    } 
    // Same status, earlier time wins (lower time value = higher priority) 
    if (f1->request_time != f2->request_time) { 
        return (f1->request_time < f2->request_time) ? 1 : -1; 
    } 
    return 0; 
} 

// Swap two flyers and update index mapping 
void swap(Flyer** a, Flyer** b, int* index_a, int* index_b, int* id_to_index) { 
    Flyer* temp = *a; 
    *a = *b; 
    *b = temp; 

    // Update index mapping 
    id_to_index[(*a)->flyer_id] = *index_a; 
    id_to_index[(*b)->flyer_id] = *index_b; 
} 

// Heapify up (for insertion) 
void heapifyUp(PriorityQueue* pq, int index) { 
    while (index > 0) { 
        int parent = (index - 1) / 2; 
        if (comparePriority(pq->flyers[index], pq->flyers[parent]) > 0) { 
            swap(&pq->flyers[index], &pq->flyers[parent],  
                 &index, &parent, pq->id_to_index); 
            index = parent; 
        } else { 
            break; 
        } 
    } 
} 

// Heapify down (for extraction) 
void heapifyDown(PriorityQueue* pq, int index) {

10 

    while (true) { 
        int largest = index; 
        int left = 2 * index + 1; 
        int right = 2 * index + 2; 

        if (left < pq->size && comparePriority(pq->flyers[left], pq->flyers[largest]) > 
0) { 
            largest = left; 
        } 
        if (right < pq->size && comparePriority(pq->flyers[right], pq-
>flyers[largest]) > 0) { 
            largest = right; 
        } 

        if (largest != index) { 
            swap(&pq->flyers[index], &pq->flyers[largest],  
                 &index, &largest, pq->id_to_index); 
            index = largest; 
        } else { 
            break; 
        } 
    } 
} 

// Insert flyer into priority queue - O(log n) 
void insertFlyer(PriorityQueue* pq, Flyer* flyer) { 
    pq->flyers[pq->size] = flyer; 
    pq->id_to_index[flyer->flyer_id] = pq->size; 
    heapifyUp(pq, pq->size); 
    pq->size++; 
} 

// Extract maximum priority flyer - O(log n) 
Flyer* extractMax(PriorityQueue* pq) { 
    if (pq->size == 0) return NULL; 

    Flyer* max = pq->flyers[0]; 
    pq->id_to_index[max->flyer_id] = -1;

11 


    pq->size--; 
    if (pq->size > 0) { 
        pq->flyers[0] = pq->flyers[pq->size]; 
        pq->id_to_index[pq->flyers[0]->flyer_id] = 0; 
        heapifyDown(pq, 0); 
    } 

    return max; 
} 

// Cancel a flyer's request - O(log n) 
void cancelRequest(PriorityQueue* pq, int flyer_id) { 
    int index = pq->id_to_index[flyer_id]; 
    if (index == -1) return; // Not found 

    pq->flyers[index]->is_cancelled = true; 
    pq->id_to_index[flyer_id] = -1; 

    // Replace with last element and heapify 
    if (index < pq->size - 1) { 
        pq->flyers[index] = pq->flyers[pq->size - 1]; 
        pq->id_to_index[pq->flyers[index]->flyer_id] = index; 
        pq->size--; 

        // Heapify both ways to maintain heap property 
        heapifyUp(pq, index); 
        heapifyDown(pq, index); 
    } else { 
        pq->size--; 
    } 
} 

// Find top k flyers - O(k log n) 
void findTopKFlyers(PriorityQueue* pq, int k, Flyer** result, int* result_size) { 
    *result_size = 0; 

    while (*result_size < k && pq->size > 0) {

12 

        Flyer* flyer = extractMax(pq); 
        if (flyer != NULL && !flyer->is_cancelled) { 
            result[*result_size] = flyer; 
            (*result_size)++; 
        } 
    } 
} 

// Helper function to print flyer results 
void printResults(Flyer** result, int result_size) { 
    for (int i = 0; i < result_size; i++) { 
        const char* status_str; 
        switch (result[i]->status) { 
            case SUPER: status_str = "Super"; break; 
            case PLATINUM: status_str = "Platinum"; break; 
            case GOLD: status_str = "Gold"; break; 
            case SILVER: status_str = "Silver"; break; 
        } 
        printf("(%s, %d, %d, %s)\n", result[i]->name, result[i]->flyer_id,  
               result[i]->request_time, status_str); 
    } 
} 

// Helper function to create a flyer 
Flyer* createFlyerHelper(const char* name, int id, int time, Status status) { 
    Flyer* f = (Flyer*)malloc(sizeof(Flyer)); 
    if (f == NULL) { 
        printf("Memory allocation failed!\n"); 
        exit(1); 
    } 
    strncpy(f->name, name, MAX_NAME - 1); 
    f->name[MAX_NAME - 1] = '\0'; 
    f->flyer_id = id; 
    f->request_time = time; 
    f->status = status; 
    f->is_cancelled = false; 
    return f; 
}

