// Function to run automated tests 
void runAutomatedTests() { 
    printf("===========================================\n"); 
    printf("Running Automated Test Cases\n"); 
    printf("===========================================\n\n"); 

    // ========== Test Case 1 ========== 
    printf("=== Test Case 1 ===\n"); 
    printf("Input:\n5 2 1\n"); 
    printf("A 1 120 Platinum\nB 5 60 Super\nC 3 140 Super\n"); 
    printf("D 2 130 Gold\nE 4 150 Silver\n5\n\n"); 

    PriorityQueue* pq1 = createPriorityQueue(); 
    insertFlyer(pq1, createFlyerHelper("A", 1, 120, PLATINUM)); 
    insertFlyer(pq1, createFlyerHelper("B", 5, 60, SUPER)); 
    insertFlyer(pq1, createFlyerHelper("C", 3, 140, SUPER)); 
    insertFlyer(pq1, createFlyerHelper("D", 2, 130, GOLD)); 
    insertFlyer(pq1, createFlyerHelper("E", 4, 150, SILVER)); 
    cancelRequest(pq1, 5); 

    Flyer* result1[100]; 
    int result_size1; 
    findTopKFlyers(pq1, 2, result1, &result_size1); 

    printf("Expected Output:\n(C, 3, 140, Super)\n(A, 1, 120, Platinum)\n\n"); 
    printf("Actual Output:\n"); 
    printResults(result1, result_size1); 
    printf("\n"); 
    destroyPriorityQueue(pq1); 

    // ========== Test Case 2 ========== 
    printf("=== Test Case 2 ===\n"); 
    printf("Input:\n4 1 2\n"); 
    printf("A 1 30 Platinum\nB 2 60 Gold\nC 3 90 Silver\nD 4 120 Super\n"); 
    printf("2\n4\n\n"); 

    PriorityQueue* pq2 = createPriorityQueue();

14 

    insertFlyer(pq2, createFlyerHelper("A", 1, 30, PLATINUM)); 
    insertFlyer(pq2, createFlyerHelper("B", 2, 60, GOLD)); 
    insertFlyer(pq2, createFlyerHelper("C", 3, 90, SILVER)); 
    insertFlyer(pq2, createFlyerHelper("D", 4, 120, SUPER)); 
    cancelRequest(pq2, 2); 
    cancelRequest(pq2, 4); 

    Flyer* result2[100]; 
    int result_size2; 
    findTopKFlyers(pq2, 1, result2, &result_size2); 

    printf("Expected Output:\n(A, 1, 30, Platinum)\n\n"); 
    printf("Actual Output:\n"); 
    printResults(result2, result_size2); 
    printf("\n"); 
    destroyPriorityQueue(pq2); 

    // ========== Test Case 3 ========== 
    printf("=== Test Case 3 ===\n"); 
    printf("Input:\n6 3 0\n"); 
    printf("A 1 100 Gold\nB 2 50 Platinum\nC 3 200 Super\n"); 
    printf("D 4 150 Super\nE 5 75 Platinum\nF 6 25 Gold\n\n"); 

    PriorityQueue* pq3 = createPriorityQueue(); 
    insertFlyer(pq3, createFlyerHelper("A", 1, 100, GOLD)); 
    insertFlyer(pq3, createFlyerHelper("B", 2, 50, PLATINUM)); 
    insertFlyer(pq3, createFlyerHelper("C", 3, 200, SUPER)); 
    insertFlyer(pq3, createFlyerHelper("D", 4, 150, SUPER)); 
    insertFlyer(pq3, createFlyerHelper("E", 5, 75, PLATINUM)); 
    insertFlyer(pq3, createFlyerHelper("F", 6, 25, GOLD)); 

    Flyer* result3[100]; 
    int result_size3; 
    findTopKFlyers(pq3, 3, result3, &result_size3); 

    printf("Expected Output:\n(D, 4, 150, Super)\n(C, 3, 200, Super)\n(B, 2, 50, 
Platinum)\n\n"); 
    printf("Actual Output:\n");

15 

    printResults(result3, result_size3); 
    printf("\n"); 
    destroyPriorityQueue(pq3); 

    // ========== Test Case 4 ========== 
    printf("=== Test Case 4 (All Same Status - Time Priority) ===\n"); 
    printf("Input:\n5 3 1\n"); 
    printf("Alice 10 500 Gold\nBob 11 300 Gold\nCharlie 12 700 Gold\n"); 
    printf("David 13 200 Gold\nEve 14 600 Gold\n12\n\n"); 

    PriorityQueue* pq4 = createPriorityQueue(); 
    insertFlyer(pq4, createFlyerHelper("Alice", 10, 500, GOLD)); 
    insertFlyer(pq4, createFlyerHelper("Bob", 11, 300, GOLD)); 
    insertFlyer(pq4, createFlyerHelper("Charlie", 12, 700, GOLD)); 
    insertFlyer(pq4, createFlyerHelper("David", 13, 200, GOLD)); 
    insertFlyer(pq4, createFlyerHelper("Eve", 14, 600, GOLD)); 
    cancelRequest(pq4, 12); 

    Flyer* result4[100]; 
    int result_size4; 
    findTopKFlyers(pq4, 3, result4, &result_size4); 

    printf("Expected Output:\n(David, 13, 200, Gold)\n(Bob, 11, 300, Gold)\n(Alice, 
10, 500, Gold)\n\n"); 
    printf("Actual Output:\n"); 
    printResults(result4, result_size4); 
    printf("\n"); 
    destroyPriorityQueue(pq4); 

    printf("===========================================\n"); 
    printf("All Tests Completed!\n"); 
    printf("===========================================\n"); 
} 

// Function to process user input 
void processUserInput() { 
    int n, k, c;

16 

    printf("===========================================\n"); 
    printf("NUA Airline Upgrade System - Manual Input\n"); 
    printf("===========================================\n\n"); 

    printf("Enter n (number of flyers), k (seats available), c (cancellations):\n"); 
    printf("Format: n k c\n> "); 
    scanf("%d %d %d", &n, &k, &c); 

    PriorityQueue* pq = createPriorityQueue(); 

    // Read n flyers 
    printf("\nEnter %d flyers (one per line):\n", n); 
    printf("Format: Name FlyerID RequestTime Status\n"); 
    printf("Status options: Super, Platinum, Gold, Silver\n"); 
    for (int i = 0; i < n; i++) { 
        Flyer* flyer = (Flyer*)malloc(sizeof(Flyer)); 
        char status_str[20]; 
        printf("Flyer %d> ", i + 1); 
        scanf("%s %d %d %s", flyer->name, &flyer->flyer_id,  
              &flyer->request_time, status_str); 
        flyer->status = stringToStatus(status_str); 
        flyer->is_cancelled = false; 
        insertFlyer(pq, flyer); 
    } 

    // Read c cancellations 
    if (c > 0) { 
        printf("\nEnter %d cancellation IDs (one per line):\n", c); 
        for (int i = 0; i < c; i++) { 
            int cancel_id; 
            printf("Cancel %d> ", i + 1); 
            scanf("%d", &cancel_id); 
            cancelRequest(pq, cancel_id); 
        } 
    } 

    // Find top k flyers 
    Flyer* result[MAX_FLYERS];

17 

    int result_size; 
    findTopKFlyers(pq, k, result, &result_size); 

    // Output results 
    printf("\n===========================================\n"); 
    printf("Output: Top %d Flyers Allowed to Board\n", k); 
    printf("===========================================\n"); 
    for (int i = 0; i < result_size; i++) { 
        const char* status_str; 
        switch (result[i]->status) { 
            case SUPER: status_str = "Super"; break; 
            case PLATINUM: status_str = "Platinum"; break; 
            case GOLD: status_str = "Gold"; break; 
            case SILVER: status_str = "Silver"; break; 
        } 
        printf("(%s, %d, %d, %s)\n", result[i]->name, result[i]->flyer_id,  
               result[i]->request_time, status_str); 
        free(result[i]); 
    } 
    printf("\n"); 

    destroyPriorityQueue(pq); 
} 

// Main function with menu 
int main(int argc, char* argv[]) { 
    // Check if running in test mode 
    if (argc > 1 && strcmp(argv[1], "test") == 0) { 
        runAutomatedTests(); 
        return 0; 
    } 

    // Interactive menu 
    printf("===========================================\n"); 
    printf("NUA Airline Upgrade System\n"); 
    printf("===========================================\n\n"); 
    printf("Select mode:\n"); 
    printf("1. Manual Input (Enter your own test case)\n");

18 

    printf("2. Run Automated Tests\n"); 
    printf("3. Exit\n\n"); 
    printf("Choice> "); 

    int choice; 
    scanf("%d", &choice); 
    printf("\n"); 

    switch (choice) { 
        case 1: 
            processUserInput(); 
            break; 
        case 2: 
            runAutomatedTests(); 
            break; 
        case 3: 
            printf("Exiting program. Goodbye!\n"); 
            break; 
        default: 
            printf("Invalid choice. Exiting.\n"); 
    } 

    return 0; 
} 

